def _load_embedded_image(encoded_lines, mode):
    image_bytes = base64.b64decode("".join(encoded_lines))
    with Image.open(io.BytesIO(image_bytes)) as img:
        return img.convert(mode)

class PondAssets:
    def __init__(self):
        self.lily_sprites = [
            _load_embedded_image(EMBEDDED_LILYPAD_1_PNG_B64, "RGBA").resize((134, 105), Image.Resampling.LANCZOS),
            _load_embedded_image(EMBEDDED_LILYPAD_2_PNG_B64, "RGBA").resize((141, 104), Image.Resampling.LANCZOS),
            _load_embedded_image(EMBEDDED_LILYPAD_3_PNG_B64, "RGBA").resize((128, 102), Image.Resampling.LANCZOS),
        ]
        self.bg = _load_embedded_image(EMBEDDED_POND_BACKGROUND_JPEG_B64, "RGB").resize(
            (LCD_WIDTH, LCD_HEIGHT),
            Image.Resampling.LANCZOS,
        )
        self.grid_x, self.grid_y = np.meshgrid(
            np.arange(LCD_WIDTH, dtype=np.float32),
            np.arange(LCD_HEIGHT, dtype=np.float32),
        )

    def _make_background(self):
        img = Image.new("RGB", (LCD_WIDTH, LCD_HEIGHT))
        pixels = []
        cx = LCD_WIDTH / 2.0
        cy = LCD_HEIGHT / 2.0
        max_dist = math.sqrt(cx * cx + cy * cy)

        for y in range(LCD_HEIGHT):
            for x in range(LCD_WIDTH):
                dx = x - cx
                dy = y - cy
                dist = math.sqrt(dx * dx + dy * dy) / max_dist
                ripple = math.sin((x * 0.11) + (y * 0.07)) * 6
                shimmer = math.sin((x * 0.035) - (y * 0.045)) * 4
                vignette = 1.0 - min(1.0, dist * 0.85)

                r = int(18 + 8 * vignette + ripple * 0.2)
                g = int(58 + 36 * vignette + ripple + shimmer)
                b = int(72 + 58 * vignette + ripple * 1.4 + shimmer)

                pixels.append((
                    max(0, min(255, r)),
                    max(0, min(255, g)),
                    max(0, min(255, b)),
                ))

        img.putdata(pixels)

        draw = ImageDraw.Draw(img, "RGBA")
        for _ in range(22):
            x = random.randint(-20, LCD_WIDTH)
            y = random.randint(-20, LCD_HEIGHT)
            radius = random.randint(16, 42)
            color = random.choice([
                (20, 90, 90, 18),
                (12, 70, 74, 22),
                (55, 120, 116, 12),
            ])
            draw.ellipse((x - radius, y - radius, x + radius, y + radius), fill=color)

        for _ in range(12):
            x = random.randint(0, LCD_WIDTH)
            y = random.randint(0, LCD_HEIGHT)
            radius = random.randint(18, 34)
            draw.ellipse(
                (x - radius, y - radius, x + radius, y + radius),
                outline=(150, 210, 205, 20),
                width=1,
            )

        return img

    def _make_lilypad_sprite(self, width, height, notch_angle=0.0, hue_shift=0):
        sprite = Image.new("RGBA", (width, height), (0, 0, 0, 0))
        draw = ImageDraw.Draw(sprite, "RGBA")

        pad_color = (72 + hue_shift, 145 + hue_shift, 76, 255)
        shadow_color = (28, 72, 34, 90)
        vein_color = (170, 220, 140, 110)

        draw.ellipse((6, 6, width - 6, height - 6), fill=shadow_color)
        draw.ellipse((0, 0, width - 10, height - 10), fill=pad_color)
        draw.ellipse((8, 6, width - 18, height - 18), fill=(94 + hue_shift, 170 + hue_shift, 90, 235))

        cx = width * 0.46
        cy = height * 0.44
        notch_len = min(width, height) * 0.55
        notch_spread = 0.28
        p1 = (cx, cy)
        p2 = (
            cx + math.cos(notch_angle - notch_spread) * notch_len,
            cy + math.sin(notch_angle - notch_spread) * notch_len,
        )
        p3 = (
            cx + math.cos(notch_angle + notch_spread) * notch_len,
            cy + math.sin(notch_angle + notch_spread) * notch_len,
        )
        draw.polygon([p1, p2, p3], fill=(0, 0, 0, 0))

        for angle in (-1.3, -0.7, -0.15, 0.45, 1.0):
            ex = cx + math.cos(angle) * (width * 0.32)
            ey = cy + math.sin(angle) * (height * 0.32)
            draw.line((cx, cy, ex, ey), fill=vein_color, width=2)

        draw.ellipse((width * 0.18, height * 0.12, width * 0.48, height * 0.34), fill=(220, 255, 220, 26))
        return sprite

assets = None

class Lilypad:
    def __init__(self, x, y, rot=0, scale=1.0):
        self.pos = [x, y]
        b = random.choice(assets.lily_sprites)
        fin_w = int(b.size[0] * 0.4 * scale)
        fin_h = int(b.size[1] * 0.4 * scale)
        b = b.resize((fin_w, fin_h), Image.Resampling.LANCZOS)
        if rot != 0:
            b = b.rotate(rot, expand=True, resample=Image.Resampling.BICUBIC)
        self.sprite = b

    def bounds(self):
        w, h = self.sprite.size
        px = int(self.pos[0] - w // 2)
        py = int(self.pos[1] - h // 2)
        return px, py, w, h

    def draw(self, img_bg):
        px, py, w, h = self.bounds()
        # Paste lilypad on the pond
        try:
            img_bg.paste(self.sprite, (px, py), self.sprite)
        except ValueError:
            pass

class Koi:
    def __init__(self, x, y):
        self.pos = [x, y]
        self.hiding_state = "normal"
        self.hide_timer = 0
        self.hide_target = None
        self.scared = random.uniform(0, 9.0)
        self.offscreen_replacement_checked = False
        self.vel = [random.uniform(-1, 1), random.uniform(-1, 1)]
        self.normalize(self.vel)
        self.vel[0] *= 2.0
        self.vel[1] *= 2.0
        
        self.num_chunks = 10
        self.segment_dist = 3.5
        
        # True comma shape, fading from head to tail tip
        self.radii = [7.0, 8.0, 7.5, 6.0, 5.0, 4.0, 3.0, 2.0, 1.0, 0.5]
        self.color = random.choice([(255, 90, 40), (220, 220, 220), (255, 170, 50), (240, 100, 40)])
        self.texture_marks = self._generate_texture_marks()
        
        self.segments = [[x, y] for _ in range(self.num_chunks)]

    def normalize(self, v):
        mag = math.sqrt(v[0]**2 + v[1]**2)
        if mag > 0:
            v[0] /= mag
            v[1] /= mag
        return mag

    def _clamp_color(self, color):
        return tuple(max(0, min(255, int(c))) for c in color)

    def _generate_texture_marks(self):
        palette = [
            (248, 244, 232),
            (255, 188, 82),
            (255, 132, 70),
            (234, 84, 48),
            (76, 56, 48),
            (34, 30, 28),
            (232, 210, 120),
        ]

        marks = []
        mark_count = random.randint(0, 3)
        body_start = 2
        body_end = max(body_start, self.num_chunks - 4)
        for _ in range(mark_count):
            seg_index = random.randint(body_start, body_end)
            side = random.choice([-1.0, 1.0])
            along = random.uniform(-0.28, 0.15)
            lateral = random.uniform(0.10, 0.42)
            radius_scale = random.uniform(0.22, 0.48) * (1.0 - seg_index / (self.num_chunks + 2))
            stretch = random.uniform(0.8, 1.35)
            tint = random.choice(palette)
            alpha = random.randint(115, 205)
            marks.append(
                {
                    "segment": seg_index,
                    "side": side,
                    "along": along,
                    "lateral": lateral,
                    "radius_scale": max(0.16, radius_scale),
                    "stretch": stretch,
                    "color": tint,
                    "alpha": alpha,
                }
            )

        return marks

    def _draw_texture(self, draw):
        if len(self.segments) < 2:
            return

        for mark in self.texture_marks:
            seg_idx = min(mark["segment"], self.num_chunks - 2)
            seg = self.segments[seg_idx]
            next_seg = self.segments[seg_idx + 1]
            dx = next_seg[0] - seg[0]
            dy = next_seg[1] - seg[1]
            mag = math.hypot(dx, dy)
            if mag < 0.001:
                angle = math.atan2(self.vel[1], self.vel[0])
                tangent_x = math.cos(angle)
                tangent_y = math.sin(angle)
            else:
                tangent_x = dx / mag
                tangent_y = dy / mag

            normal_x = -tangent_y
            normal_y = tangent_x
            body_r = self.radii[seg_idx]
            center_x = (
                seg[0]
                + tangent_x * body_r * mark["along"]
                + normal_x * body_r * mark["lateral"] * mark["side"]
            )
            center_y = (
                seg[1]
                + tangent_y * body_r * mark["along"]
                + normal_y * body_r * mark["lateral"] * mark["side"]
            )

            rx = max(1.2, body_r * mark["radius_scale"] * mark["stretch"])
            ry = max(1.0, body_r * mark["radius_scale"])
            color = (*mark["color"], mark["alpha"])
            draw.ellipse((center_x - rx, center_y - ry, center_x + rx, center_y + ry), fill=color)

    def update(self, target=None, flee_points=None, lilypads=None):
        if not hasattr(self, 'hiding_state'):
            self.hiding_state = "normal" # normal, hiding, hidden, returning
            self.hide_timer = 0
            self.hide_target = None
            
        speed = 2.5
        ax, ay = 0, 0
        
        if flee_points and self.hiding_state in ("normal", "returning"):
            # A touch happened! Scatter and hide!
            self.hiding_state = "hiding"
            
            touch_x, touch_y = flee_points[0]
            
            if self.scared <= 1.0:
                # Swim TOWARDS the touch
                self.hide_target = [touch_x + random.uniform(-10, 10), touch_y + random.uniform(-10, 10)]
            elif self.scared < 5.0:
                # Move away, but not off screen
                angle = math.atan2(self.pos[1] - touch_y, self.pos[0] - touch_x) + random.uniform(-0.5, 0.5)
                dist = 60 + self.scared * 10
                hx = self.pos[0] + math.cos(angle) * dist
                hy = self.pos[1] + math.sin(angle) * dist
                # Clamp to screen bounds
                hx = max(20, min(LCD_WIDTH - 20, hx))
                hy = max(20, min(LCD_HEIGHT - 20, hy))
                self.hide_target = [hx, hy]
            else:
                # Very scared (5-9)! Hide under lilypad or offscreen
                if lilypads and random.random() > 0.3:
                    # hide under lilypad
                    pad = random.choice(lilypads)
                    self.hide_target = [pad.pos[0] + random.uniform(-10, 10), pad.pos[1] + random.uniform(-10, 10)]
                else:
                    # hide offscreen
                    angle = math.atan2(self.pos[1] - touch_y, self.pos[0] - touch_x) + random.uniform(-0.5, 0.5)
                    dist = (LCD_WIDTH / 2.0) + (self.scared / 9.0) * (LCD_WIDTH)
                    self.hide_target = [self.pos[0] + math.cos(angle)*dist, self.pos[1] + math.sin(angle)*dist]
                
        if self.hiding_state == "normal":
            # Basic wandering behavior
            wander_angle = random.uniform(-0.4, 0.4)
            current_angle = math.atan2(self.vel[1], self.vel[0])
            new_angle = current_angle + wander_angle
            
            # Keep them in bounds gently
            cx, cy = LCD_WIDTH/2, LCD_HEIGHT/2
            dx, dy = cx - self.pos[0], cy - self.pos[1]
            dist_center = math.sqrt(dx**2 + dy**2)
            if dist_center > LCD_WIDTH/2 - 20:
                ax += dx * 0.05
                ay += dy * 0.05
                
            self.vel[0] = math.cos(new_angle) * speed + ax
            self.vel[1] = math.sin(new_angle) * speed + ay
            
        elif self.hiding_state == "hiding":
            speed = 3.0 + (self.scared / 9.0) * 5.0 # speed proportional to scared
            dx = self.hide_target[0] - self.pos[0]
            dy = self.hide_target[1] - self.pos[1]
            dist = math.sqrt(dx**2 + dy**2)
            
            if dist < 20:
                # reached hiding spot!
                self.hiding_state = "hidden"
                self.hide_timer = time.time() + (self.scared / 9.0) * 10.0
                # Do not stop completely, just slow down
                speed = 0.6
            else:
                # Steer towards target
                tx, ty = (dx/dist), (dy/dist)
                
                # Blend current velocity with target direction
                current_angle = math.atan2(self.vel[1], self.vel[0])
                target_angle = math.atan2(ty, tx)
                
                # Turn quickly towards target
                diff = (target_angle - current_angle + math.pi) % (2*math.pi) - math.pi
                new_angle = current_angle + diff * 0.2
                
                self.vel[0] = math.cos(new_angle) * speed
                self.vel[1] = math.sin(new_angle) * speed

        elif self.hiding_state == "hidden":
            speed = 0.6 # gently wiggle/wander around hiding spot
            wander_angle = random.uniform(-0.6, 0.6)
            current_angle = math.atan2(self.vel[1], self.vel[0])
            new_angle = current_angle + wander_angle
            
            # Keep clustered near hide_target
            dx = self.hide_target[0] - self.pos[0]
            dy = self.hide_target[1] - self.pos[1]
            dist_to_target = math.sqrt(dx**2 + dy**2)
            if dist_to_target > 15:
                ax += (dx/max(1, dist_to_target)) * 0.1
                ay += (dy/max(1, dist_to_target)) * 0.1
                
            self.vel[0] = math.cos(new_angle) * speed + ax
            self.vel[1] = math.sin(new_angle) * speed + ay
            
            if time.time() > self.hide_timer:
                self.hiding_state = "returning"
                speed = 1.0
                
        elif self.hiding_state == "returning":
            speed = 1.0 # creep back in slowly
            
            # Wander slowly but prefer center
            wander_angle = random.uniform(-0.5, 0.5)
            current_angle = math.atan2(self.vel[1], self.vel[0])
            new_angle = current_angle + wander_angle
            
            cx, cy = LCD_WIDTH/2, LCD_HEIGHT/2
            dx, dy = cx - self.pos[0], cy - self.pos[1]
            dist_center = math.sqrt(dx**2 + dy**2)
            if dist_center > LCD_WIDTH/2 - 50: # stronger pull to center
                ax += dx * 0.08
                ay += dy * 0.08
            else:
                self.hiding_state = "normal" # we are back!
                
            self.vel[0] = math.cos(new_angle) * speed + ax
            self.vel[1] = math.sin(new_angle) * speed + ay

        if speed > 0:
            self.normalize(self.vel)
            self.vel[0] *= speed
            self.vel[1] *= speed
            
            self.pos[0] += self.vel[0]
            self.pos[1] += self.vel[1]
            
            # Kinematic segments chase the head
            self.segments[0] = list(self.pos)
            for i in range(1, len(self.segments)):
                s_dx = self.segments[i-1][0] - self.segments[i][0]
                s_dy = self.segments[i-1][1] - self.segments[i][1]
                dist = math.sqrt(s_dx**2 + s_dy**2)
                if dist > self.segment_dist:
                    self.segments[i][0] += (s_dx/dist) * (dist - self.segment_dist)
                    self.segments[i][1] += (s_dy/dist) * (dist - self.segment_dist)

    def _draw_shape(
        self,
        draw,
        fill_color,
        offset=(0.0, 0.0),
        body_scale=1.0,
        tail_scale=1.0,
        fin_scale=1.0,
        draw_eyes=True,
        eye_color=(0, 0, 0),
    ):
        ox, oy = offset

        last = self.segments[-1]
        prev = self.segments[-2]
        ang = math.atan2(last[1] - prev[1], last[0] - prev[0])
        t_len = 14 * tail_scale
        t_spread = 0.5
        last_pt = (last[0] + ox, last[1] + oy)
        p1 = (
            last_pt[0] + math.cos(ang - t_spread) * t_len,
            last_pt[1] + math.sin(ang - t_spread) * t_len,
        )
        p2 = (
            last_pt[0] + math.cos(ang + t_spread) * t_len,
            last_pt[1] + math.sin(ang + t_spread) * t_len,
        )
        p3 = (
            last_pt[0] + math.cos(ang) * (t_len * 0.3),
            last_pt[1] + math.sin(ang) * (t_len * 0.3),
        )
        draw.polygon([last_pt, p1, p3, p2], fill=fill_color)

        f_seg = self.segments[2]
        f_prev = self.segments[1]
        f_ang = math.atan2(f_prev[1] - f_seg[1], f_prev[0] - f_seg[0])
        flen = 10 * fin_scale
        f_width = 5 * fin_scale

        f_seg_pt = (f_seg[0] + ox, f_seg[1] + oy)
        fx1 = f_seg_pt[0] + math.cos(f_ang - math.pi/2 - 0.4) * ((self.radii[2] * body_scale) + flen)
        fy1 = f_seg_pt[1] + math.sin(f_ang - math.pi/2 - 0.4) * ((self.radii[2] * body_scale) + flen)
        draw.polygon(
            [
                f_seg_pt,
                (fx1, fy1),
                (
                    f_seg_pt[0] + math.cos(f_ang) * f_width,
                    f_seg_pt[1] + math.sin(f_ang) * f_width,
                ),
            ],
            fill=fill_color,
        )

        fx2 = f_seg_pt[0] + math.cos(f_ang + math.pi/2 + 0.4) * ((self.radii[2] * body_scale) + flen)
        fy2 = f_seg_pt[1] + math.sin(f_ang + math.pi/2 + 0.4) * ((self.radii[2] * body_scale) + flen)
        draw.polygon(
            [
                f_seg_pt,
                (fx2, fy2),
                (
                    f_seg_pt[0] + math.cos(f_ang) * f_width,
                    f_seg_pt[1] + math.sin(f_ang) * f_width,
                ),
            ],
            fill=fill_color,
        )

        for i in reversed(range(self.num_chunks)):
            seg = self.segments[i]
            r = self.radii[i] * body_scale
            sx = seg[0] + ox
            sy = seg[1] + oy
            draw.ellipse((sx-r, sy-r, sx+r, sy+r), fill=fill_color)

            if i == 0 and draw_eyes:
                h_ang = math.atan2(self.vel[1], self.vel[0])
                ex1 = sx + math.cos(h_ang - math.pi/2.5) * (r * 0.7)
                ey1 = sy + math.sin(h_ang - math.pi/2.5) * (r * 0.7)
                ex2 = sx + math.cos(h_ang + math.pi/2.5) * (r * 0.7)
                ey2 = sy + math.sin(h_ang + math.pi/2.5) * (r * 0.7)
                draw.ellipse((ex1-1.5, ey1-1.5, ex1+1.5, ey1+1.5), fill=eye_color)
                draw.ellipse((ex2-1.5, ey2-1.5, ex2+1.5, ey2+1.5), fill=eye_color)
        
    def draw(self, img_bg):
        shadow_layer = Image.new("RGBA", img_bg.size, (0, 0, 0, 0))
        shadow_draw = ImageDraw.Draw(shadow_layer, "RGBA")
        shadow_offset = (4.0, 5.0)
        self._draw_shape(
            shadow_draw,
            (10, 28, 22, 68),
            offset=shadow_offset,
            body_scale=1.08,
            tail_scale=0.96,
            fin_scale=0.88,
            draw_eyes=False,
        )

        composited = Image.alpha_composite(img_bg.convert("RGBA"), shadow_layer)
        img_bg.paste(composited.convert("RGB"))

        body_layer = Image.new("RGBA", img_bg.size, (0, 0, 0, 0))
        draw = ImageDraw.Draw(body_layer, "RGBA")
        self._draw_shape(draw, self.color)
        self._draw_texture(draw)
        composited = Image.alpha_composite(img_bg.convert("RGBA"), body_layer)
        img_bg.paste(composited.convert("RGB"))

class Pond:
    def __init__(self):
        self.lilypads = [
            Lilypad(40, 40, rot=random.uniform(0, 360), scale=0.8),
            Lilypad(200, 60, rot=random.uniform(0, 360), scale=1.2),
            Lilypad(50, 200, rot=random.uniform(0, 360), scale=0.9),
            Lilypad(180, 190, rot=random.uniform(0, 360), scale=1.1)
        ]
        
        self.fish = [Koi(LCD_WIDTH/2 + random.uniform(-50,50), LCD_HEIGHT/2 + random.uniform(-50,50)) for _ in range(6)]
        self.ripples = [] 
        self.touch_points = []
        self.start_time = time.time()

    def _spawn_koi_from_offscreen(self):
        margin = random.uniform(24.0, 42.0)
        edge = random.choice(("left", "right", "top", "bottom"))

        if edge == "left":
            x = -margin
            y = random.uniform(15.0, LCD_HEIGHT - 15.0)
        elif edge == "right":
            x = LCD_WIDTH + margin
            y = random.uniform(15.0, LCD_HEIGHT - 15.0)
        elif edge == "top":
            x = random.uniform(15.0, LCD_WIDTH - 15.0)
            y = -margin
        else:
            x = random.uniform(15.0, LCD_WIDTH - 15.0)
            y = LCD_HEIGHT + margin

        koi = Koi(x, y)
        target_x = LCD_WIDTH * 0.5 + random.uniform(-40.0, 40.0)
        target_y = LCD_HEIGHT * 0.5 + random.uniform(-40.0, 40.0)
        dx = target_x - x
        dy = target_y - y
        dist = math.hypot(dx, dy)
        if dist > 0.001:
            koi.vel = [(dx / dist) * 2.1, (dy / dist) * 2.1]
        koi.pos = [x, y]
        koi.segments = [[x, y] for _ in range(koi.num_chunks)]
        return koi

    def _should_replace_offscreen_koi(self, koi):
        if koi.scared <= 7.0:
            return False

        margin = 18.0
        outside = (
            koi.pos[0] < -margin
            or koi.pos[0] > LCD_WIDTH + margin
            or koi.pos[1] < -margin
            or koi.pos[1] > LCD_HEIGHT + margin
        )
        if not outside:
            koi.offscreen_replacement_checked = False
            return False

        if koi.offscreen_replacement_checked:
            return False

        koi.offscreen_replacement_checked = True
        return random.random() < 0.5

    def _apply_floor_shimmer(self, img, now):
        img_arr = np.array(img, dtype=np.float32)
        xs = assets.grid_x
        ys = assets.grid_y

        radial_x = (xs - LCD_WIDTH * 0.5) / (LCD_WIDTH * 0.56)
        radial_y = (ys - LCD_HEIGHT * 0.5) / (LCD_HEIGHT * 0.56)
        radial_mask = np.clip(1.0 - np.hypot(radial_x, radial_y), 0.0, 1.0)
        depth_mask = 0.35 + 0.65 * np.clip((ys - (LCD_HEIGHT * 0.08)) / (LCD_HEIGHT * 0.92), 0.0, 1.0)
        shimmer_mask = np.clip((radial_mask * 0.75) + 0.25, 0.0, 1.0) * depth_mask

        drift_x = xs + np.sin((ys * 0.026) - now * 0.95) * 11.0
        drift_y = ys + np.sin((xs * 0.021) + now * 0.75) * 8.0

        wave1 = np.sin(drift_x * 0.102 + now * 3.0 + np.sin(drift_y * 0.054 - now * 1.2) * 1.9)
        wave2 = np.sin((drift_x + drift_y) * 0.064 - now * 3.5)
        wave3 = np.sin(np.hypot(drift_x - LCD_WIDTH * 0.58, drift_y - LCD_HEIGHT * 0.22) * 0.12 - now * 2.4)
        wave4 = np.sin((drift_x * 0.036) - (drift_y * 0.071) + now * 1.6)

        caustic = np.maximum(0.0, wave1 + wave2 * 0.82 + wave3 * 0.72 + wave4 * 0.45 - 1.05)
        caustic = (caustic ** 1.48) * shimmer_mask * 56.0

        sun_glow = np.maximum(
            0.0,
            np.sin((xs * 0.031) - (ys * 0.043) + now * 1.8)
            + np.sin((xs * 0.018) + (ys * 0.026) - now * 1.15)
            - 0.1,
        )
        sun_glow = (sun_glow ** 1.65) * (0.3 + radial_mask * 0.7) * (0.45 + depth_mask * 0.55) * 16.0

        img_arr[..., 0] = np.clip(img_arr[..., 0] + caustic * 0.44 + sun_glow * 0.32, 0, 255)
        img_arr[..., 1] = np.clip(img_arr[..., 1] + caustic * 0.92 + sun_glow * 0.58, 0, 255)
        img_arr[..., 2] = np.clip(img_arr[..., 2] + caustic * 0.66 + sun_glow * 0.40, 0, 255)

        return Image.fromarray(img_arr.astype(np.uint8), "RGB")

    def _apply_ripple_distortion(self, img, now):
        if not self.ripples:
            return img

        src = np.asarray(img, dtype=np.uint8)
        xs = assets.grid_x
        ys = assets.grid_y
        offset_x = np.zeros_like(xs)
        offset_y = np.zeros_like(ys)
        highlight = np.zeros_like(xs)

        for rx, ry, rad, alpha in self.ripples:
            dx = xs - rx
            dy = ys - ry
            dist = np.hypot(dx, dy)
            safe_dist = np.maximum(dist, 1.0)
            ring_width = 5.5 + (rad * 0.02)
            ring = np.exp(-((dist - rad) ** 2) / (2.0 * ring_width * ring_width))
            wave = np.sin((dist - rad) * 0.85 - now * 10.0)
            strength = ring * wave * alpha * (3.5 + rad * 0.015)

            offset_x += (dx / safe_dist) * strength
            offset_y += (dy / safe_dist) * strength * 0.7
            highlight += ring * np.clip(wave, 0.0, 1.0) * alpha * 18.0

        sample_x = np.clip(np.rint(xs - offset_x), 0, LCD_WIDTH - 1).astype(np.int16)
        sample_y = np.clip(np.rint(ys - offset_y), 0, LCD_HEIGHT - 1).astype(np.int16)

        refracted = src[sample_y, sample_x].astype(np.float32)
        refracted[..., 0] = np.clip(refracted[..., 0] + highlight * 0.30, 0, 255)
        refracted[..., 1] = np.clip(refracted[..., 1] + highlight * 0.65, 0, 255)
        refracted[..., 2] = np.clip(refracted[..., 2] + highlight * 0.90, 0, 255)

        return Image.fromarray(refracted.astype(np.uint8), "RGB")

    def _apply_lilypad_ripple_reflection(self, img, now):
        if not self.ripples:
            return img

        base = img.convert("RGBA")

        for pad in self.lilypads:
            px, py, w, h = pad.bounds()
            if px >= LCD_WIDTH or py >= LCD_HEIGHT or px + w <= 0 or py + h <= 0:
                continue

            sprite = pad.sprite
            sprite_arr = np.array(sprite, dtype=np.uint8)
            alpha = sprite_arr[..., 3].astype(np.float32) / 255.0
            if not np.any(alpha > 0.05):
                continue

            local_x, local_y = np.meshgrid(
                np.arange(w, dtype=np.float32) + px,
                np.arange(h, dtype=np.float32) + py,
            )
            response = np.zeros((h, w), dtype=np.float32)

            for rx, ry, rad, ripple_alpha in self.ripples:
                dx = local_x - rx
                dy = local_y - ry
                dist = np.hypot(dx, dy)
                ring_width = 7.5 + (rad * 0.035)
                ring = np.exp(-((dist - rad) ** 2) / (2.0 * ring_width * ring_width))
                wave = np.sin((dist - rad) * 0.62 - now * 7.5)
                response += ring * wave * ripple_alpha

            if not np.any(np.abs(response) > 0.01):
                continue

            rim_mask = np.clip(alpha * (1.0 - alpha) * 5.0, 0.0, 1.0)
            pad_mask = np.clip(alpha * 0.38 + rim_mask * 0.62, 0.0, 1.0)
            positive = np.clip(response, 0.0, 1.0) * pad_mask
            negative = np.clip(-response, 0.0, 1.0) * pad_mask

            overlay = np.zeros((h, w, 4), dtype=np.uint8)
            overlay[..., 0] = np.clip(positive * 150.0, 0, 255).astype(np.uint8)
            overlay[..., 1] = np.clip(positive * 185.0, 0, 255).astype(np.uint8)
            overlay[..., 2] = np.clip(positive * 175.0, 0, 255).astype(np.uint8)
            overlay[..., 3] = np.clip(positive * 34.0 + negative * 18.0, 0, 255).astype(np.uint8)

            if not np.any(overlay[..., 3] > 0):
                continue

            overlay_img = Image.fromarray(overlay, "RGBA")
            try:
                base.alpha_composite(overlay_img, (px, py))
            except ValueError:
                pass

        return base.convert("RGB")
    
    def add_ripple(self, x, y):
        self.ripples.append([x, y, 0, 1.0])
        self.touch_points.append({"pos":(x,y), "life":0.5})

    def update(self):
        active_touches = [t["pos"] for t in self.touch_points]

        updated_fish = []
        for f in self.fish:
            f.update(flee_points=active_touches, lilypads=self.lilypads)
            if self._should_replace_offscreen_koi(f):
                updated_fish.append(self._spawn_koi_from_offscreen())
            else:
                updated_fish.append(f)
        self.fish = updated_fish
            
        for r in self.ripples:
            r[2] += 2.0 
            r[3] -= 0.02 
        self.ripples = [r for r in self.ripples if r[3] > 0]
        
        for t in self.touch_points:
            t["life"] -= 0.05
        self.touch_points = [t for t in self.touch_points if t["life"] > 0]

    def render(self):
        now = time.time() - self.start_time
        img = assets.bg.copy()
        img = self._apply_floor_shimmer(img, now)
        
        for f in self.fish:
            f.draw(img)

        img = self._apply_ripple_distortion(img, now)
            
        for pad in self.lilypads:
            pad.draw(img)

        img = self._apply_lilypad_ripple_reflection(img, now)
            
        return img

# Shared state
touch_x, touch_y, is_touched = -1, -1, False

def touch_thread(driver):
    global touch_x, touch_y, is_touched
    try:
        if "gpiod" in globals():
            from gpiod.line import Direction, Value
            rst = driver.chip.request_lines(config={17: gpiod.LineSettings(direction=Direction.OUTPUT, output_value=Value.INACTIVE)}, consumer="tr")
            rst.set_value(17, Value.INACTIVE)
            time.sleep(0.01)
            rst.set_value(17, Value.ACTIVE)
            time.sleep(0.05)
            
        bus = smbus2.SMBus(3)
        try:
            bus.write_byte_data(0x15, 0xFE, 0x01) 
            bus.write_byte_data(0x15, 0xFA, 0x41) 
        except:
            pass

        while True:
            try:
                data = bus.read_i2c_block_data(0x15, 0x01, 6)
                if data[1] > 0: 
                    x = ((data[2] & 0x0F) << 8) | data[3]
                    y = ((data[4] & 0x0F) << 8) | data[5]
                    x = (LCD_WIDTH - 1) - x
                    touch_x, touch_y, is_touched = x, y, True
                else:
                    is_touched = False
            except Exception:
                is_touched = False
            time.sleep(0.02)
    except Exception as e:
        pass

def main():
    global assets, is_touched
    print("Loading assets...")
    assets = PondAssets()
    
    print("Initializing display...")
    driver = DisplayDriver(spi_speed_hz=80000000)
    driver.init()
    
    print("Starting touch thread...")
    t = threading.Thread(target=touch_thread, args=(driver,), daemon=True)
    t.start()
    
    pond = Pond()
    
    print("Running Koi pond...")
    try:
        last_touch = False
        while True:
            t0 = time.time()
            if is_touched and not last_touch:
                pond.add_ripple(touch_x, touch_y)
            last_touch = is_touched
                
            pond.update()
            img = pond.render()
            
            img_arr = np.array(img.convert("RGB"), dtype=np.uint16)
            r = (img_arr[..., 0] >> 3) << 11
            g = (img_arr[..., 1] >> 2) << 5
            b = (img_arr[..., 2] >> 3)
            rgb565 = r | g | b
            driver.draw_frame(rgb565.byteswap().tobytes())
            
            # Simple frame limiter ~30fps
            elapsed = time.time() - t0
            if elapsed < 0.033:
                time.sleep(0.033 - elapsed)
            
    except KeyboardInterrupt:
        print("Exiting.")
    except Exception as e:
        import traceback
        with open("/tmp/koi_crash_trace.log", "w") as f:
            traceback.print_exc(file=f)
        raise

if __name__ == "__main__":
    main()
